package main

import (
	"bufio"
	"fmt"
	"os"
	"path/filepath"
	"runtime"
	"strings"
)

// defaultConfigPath returns the platform-appropriate config location.
func defaultConfigPath() string {
	switch runtime.GOOS {
	case "windows":
		pd := os.Getenv("PROGRAMDATA")
		if pd == "" {
			pd = `C:\ProgramData`
		}
		return filepath.Join(pd, "zharp-collector", "config.yaml")
	case "darwin":
		home, _ := os.UserHomeDir()
		return filepath.Join(home, ".config", "zharp-collector", "config.yaml")
	default:
		return "/etc/zharp-collector/config.yaml"
	}
}

// ensureConfig is called before the OTel collector starts.
// It injects --config into os.Args so the collector always has one,
// running an interactive wizard on first use if needed.
func ensureConfig() {
	// Never interfere with help/version/subcommand flags.
	for _, a := range os.Args[1:] {
		if a == "--help" || a == "-h" || a == "--version" || a == "components" || a == "validate" {
			return
		}
	}

	// --config already supplied — nothing to do.
	for _, a := range os.Args[1:] {
		if a == "--config" || strings.HasPrefix(a, "--config=") {
			return
		}
	}

	cfgPath := defaultConfigPath()

	// Config already exists — inject silently.
	if _, err := os.Stat(cfgPath); err == nil {
		os.Args = append(os.Args, "--config", "file:"+cfgPath)
		return
	}

	// First run: guide the user through setup, write config, then continue.
	runSetupWizard(cfgPath)
	os.Args = append(os.Args, "--config", "file:"+cfgPath)
}

// ── wizard ────────────────────────────────────────────────────────────────────

func runSetupWizard(cfgPath string) {
	fmt.Println()
	fmt.Println("  ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
	fmt.Println("       Zharp Collector  ·  First-Run Setup         ")
	fmt.Println("  ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
	fmt.Println()
	fmt.Println("  No configuration found. Let's create one.")
	fmt.Printf("  Config will be saved to: %s\n", cfgPath)
	fmt.Println()

	// ── api key ───────────────────────────────────────────────────────────────
	fmt.Println("  Get your API key at: https://zharp.io/settings/api-keys")
	fmt.Println()
	apiKey := ""
	for apiKey == "" {
		apiKey = wizardPrompt("API key", "")
		if apiKey == "" {
			fmt.Println("  [!] API key is required.")
		}
	}

	// ── service selection ─────────────────────────────────────────────────────
	fmt.Println()
	fmt.Println("  Host metrics (CPU, memory, disk, network) are always collected.")
	fmt.Println()

	type svcOption struct {
		name     string
		receiver string
		block    string
	}

	options := []svcOption{
		{
			name: "PostgreSQL", receiver: "postgresql",
			block: `
  postgresql:
    endpoint: localhost:5432
    username: zharp_monitor
    password: "${env:PG_PASSWORD}"
    collection_interval: 30s
    tls:
      insecure: true`,
		},
		{
			name: "MySQL / MariaDB", receiver: "mysql",
			block: `
  mysql:
    endpoint: localhost:3306
    username: zharp_monitor
    password: "${env:MYSQL_PASSWORD}"
    collection_interval: 30s`,
		},
		{
			name: "Redis", receiver: "redis",
			block: `
  redis:
    endpoint: localhost:6379
    collection_interval: 30s`,
		},
		{
			name: "MongoDB", receiver: "mongodb",
			block: `
  mongodb:
    hosts:
      - endpoint: localhost:27017
    collection_interval: 30s
    tls:
      insecure: true`,
		},
	}

	metricsReceivers := []string{"hostmetrics"}
	var extraBlocks []string

	for _, opt := range options {
		ans := wizardPrompt(fmt.Sprintf("Monitor %s? [y/N]", opt.name), "n")
		if strings.EqualFold(strings.TrimSpace(ans), "y") {
			metricsReceivers = append(metricsReceivers, opt.receiver)
			extraBlocks = append(extraBlocks, opt.block)
		}
	}

	// ── write config ──────────────────────────────────────────────────────────
	if err := os.MkdirAll(filepath.Dir(cfgPath), 0o755); err != nil {
		fmt.Fprintf(os.Stderr, "\n  [!] Cannot create config directory: %v\n", err)
		if runtime.GOOS == "windows" {
			fmt.Println("  Run this program as Administrator.")
		} else {
			fmt.Println("  Run with sudo.")
		}
		waitEnter()
		os.Exit(1)
	}

	f, err := os.OpenFile(cfgPath, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0o600)
	if err != nil {
		fmt.Fprintf(os.Stderr, "\n  [!] Cannot write config: %v\n", err)
		waitEnter()
		os.Exit(1)
	}

	writeConfig(f, apiKey, metricsReceivers, extraBlocks)
	f.Close()

	fmt.Println()
	fmt.Printf("  [+] Config saved  →  %s\n", cfgPath)
	fmt.Println("  [+] Starting collector...")
	fmt.Println()
}

func writeConfig(f *os.File, apiKey string, metricsReceivers []string, extraBlocks []string) {
	w := func(s string) { fmt.Fprint(f, s) }

	w("## Zharp Collector — generated by first-run wizard\n")
	w("## Edit this file then restart the service to apply changes.\n\n")

	w("extensions:\n  health_check:\n    endpoint: 0.0.0.0:13133\n\n")

	w("receivers:\n")
	w("  hostmetrics:\n    collection_interval: 60s\n    scrapers:\n")
	w("      cpu:\n      memory:\n      disk:\n      network:\n      load:\n")
	for _, b := range extraBlocks {
		w(b + "\n")
	}

	w("\nprocessors:\n")
	w("  batch:\n    send_batch_size: 500\n    timeout: 5s\n")
	w("  memory_limiter:\n    limit_mib: 128\n    spike_limit_mib: 32\n    check_interval: 5s\n")
	w("  resourcedetection:\n    detectors: [system, env]\n    timeout: 5s\n")

	w("\nexporters:\n")
	fmt.Fprintf(f, "  zharp:\n    api_key: \"%s\"\n", apiKey)

	w("\nservice:\n  extensions: [health_check]\n  pipelines:\n")
	fmt.Fprintf(f, "    metrics:\n      receivers: [%s]\n", strings.Join(metricsReceivers, ", "))
	w("      processors: [memory_limiter, resourcedetection, batch]\n")
	w("      exporters: [zharp]\n")
}

var wizardScanner = bufio.NewScanner(os.Stdin)

func wizardPrompt(label, fallback string) string {
	if fallback != "" {
		fmt.Printf("  > %s [%s]: ", label, fallback)
	} else {
		fmt.Printf("  > %s: ", label)
	}
	if wizardScanner.Scan() {
		v := strings.TrimSpace(wizardScanner.Text())
		if v == "" {
			return fallback
		}
		return v
	}
	return fallback
}

// waitEnter keeps the console window open on Windows when double-clicked.
func waitEnter() {
	fmt.Print("\n  Press Enter to close...")
	wizardScanner.Scan()
}
